        .result-label {
            font-size: 0.75rem;
            text-transform: uppercase;
            letter-spacing: 0.05em;
            color: var(--text-muted);
        }
        .breakdown {
            margin-top: 1rem;
            padding-top: 1rem;
            border-top: 1px dashed var(--border);
        }
        .breakdown-item {
            display: flex;
            justify-content: space-between;
            padding: 0.25rem 0;
            font-size: 0.9rem;
        }
        .total-item {
            font-weight: 600;
            color: var(--text);
        }
        .monthly-item {
            color: var(--success);
        }
        .comparison-section {
            margin-top: 1.5rem;
            border-top: 2px solid var(--border);
            padding-top: 1.5rem;
        }
        .tab-group {
            display: flex;
            gap: 0.5rem;
            margin-bottom: 1rem;
            border-bottom: 1px solid var(--border);
        }
        .tab-btn {
            background: none;
            border: none;
            padding: 0.5rem 1rem;
            cursor: pointer;
            font-weight: 600;
            color: var(--text-muted);
            border-bottom: 2px solid transparent;
            transition: all 0.2s;
        }
        .tab-btn.active {
            color: var(--primary);
            border-bottom-color: var(--primary);
        }
        .comparison-content {
            display: none;
            background: var(--bg);
            padding: 1rem;
            border-radius: 0.5rem;
        }
        .comparison-content.active { display: block; }
        @media (max-width: 600px) {
            .row { grid-template-columns: 1fr; }
        }
    </style>
